CODE_EXAMPLE:
// Before
class TimesheetEntry {
  Date getDate() { ... }
  int getHours() { ... }
  void approve() { ... }
}

// After
interface Billable {
  int getHours();
}

class TimesheetEntry implements Billable {
  Date getDate() { ... }
  public int getHours() { ... }
  void approve() { ... }
}

// Client
Billable entry = new TimesheetEntry();

UNIT_TEST_EXAMPLE:
@Test
public void testExtractInterface() {
  Billable item = new TimesheetEntry();
  item.setHours(8);
  assertEquals(8, item.getHours());
}
